export function runScenario(scenario: any): any {
  const basePremiums: Record<string, number> = {
    sword: 100,
    amulet: 60,
    staff: 80,
    potion: 40,
    rune: 25,
    moonstone: 25,
  };

  const results = scenario.steps.map((step: any) => {
    if (step.op === "quote") {
      if (step.items.length === 0) {
        return { premium: 5 };
      }
      const item = step.items[0];
      const base = basePremiums[item.type] || 0;
      const firstInsurance = base * 0.10;
      return { premium: Math.ceil(base + firstInsurance + 5) };
    }
    return {};
  });
  return { results };
}

